head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.v_auth = false;
scwin.v_bugetCd = '';
scwin.v_bugetNm = '';
scwin.empNo = scwin.memJson.empNo; // 서버 데이터
scwin.userId = scwin.memJson.empNo; // 서버 데이터
scwin.vLoginCoCd 		= $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd; // 소속 자회사  	
scwin.vLoginCoClsCd 	= $c.gus.cfIsNull(scwin.memJson.coClsCd)?'':scwin.memJson.coClsCd;//회계_회사구분('CO035' : 0:동부 EXPRESS)	
scwin.vUserHomeClsCd	= scwin.memJson.userHomeClsCd;        // 사용자소속구분코드
scwin.vCoCd             = $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd; // 회사코드 	
scwin.isSubCompany = false;
scwin.privAdmin = scwin.memJson.privAdmin; // 서버 데이터, 기본값 'F'
scwin.txtCoClsCd = "";

scwin.isStart = false;
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "CO001", compID : "acb_srchCntlUnitClsCd,gr_master:cntlUnitClsCd"}
    ];
    $c.data.setCommonCode(codeOptions);
};

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    scwin.f_FieldClear();
    //조회권한체크
    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn([btn_detail]);
	scwin.f_RetrieveAuth();
	scwin.f_setCompanyInfo();

    //***************************************************************
	//2013.03.29 hurrah015
	//예산통제부서 조회
	scwin.f_retrieveBugetAcctDeptCd();
};

scwin.ondataload = function(){
    let cnt = dlt_commonCodeCO001.getRowCount();
    for (let i = 0; i < cnt; i++){
        let cdNm = dlt_commonCodeCO001.getCellData(i, "cdNm")
        if (cdNm == ""){
            dlt_commonCodeCO001.removeRow(i)
        }
    }
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
	if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
		scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
		scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
	}
    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

// -------------------------------------------------------------------------
// 회사 입력 팝업 
// -------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
	await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc
								,ed_coCd.getValue(), ""
								,pWinCloseTF,null,null,null,null
								,null,null,null,null,null);   
} 

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    // SET	 
	if(rtnList != null ) { 
		if (rtnList[0] == "N/A") return; 

		ed_coCd.setValue(rtnList[0]);	// 코드
		ed_coNm.setValue(rtnList[5]); // 회사명 
		scwin.txtCoClsCd=rtnList[1];	// 회사구분   

	}else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
		scwin.txtCoClsCd="";
	}

    if(ed_coCd.getValue() > ACConstants.CO_CD_DONGBU)  {  	// 자회사 회계 시스템 
		scwin.isSubCompany = true;
	}else{
		scwin.isSubCompany = false;
	}

    if(scwin.isStart == true) {
        if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company]);
        }else {
            $c.gus.cfDisableBtn([ed_coCd,ed_coNm,btn_company]);   
        } 
    }
    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 예산통제부서 조회 
// commonPopUp.xml에 조회ID(retrieveAcEmpInfo1) 추가
//-------------------------------------------------------------------------
scwin.f_retrieveBugetAcctDeptCd = function() {
    const params = {
        sysCd:"CommonEBC", 
        queryId:"retrieveAcEmpInfo1",
        param1:scwin.empNo,
        param2:ed_coCd.getValue(),
        param3:scwin.vLoginCoClsCd,
    };

    //데이터셋에 정보설정
    dma_searchBuget.setJSON(params);

    $c.sbm.execute(sbm_getBuget);
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
	$c.gus.cfInitObjects(tbl_search,[ica_srchBudgetYm,ica_srchBudgetYmTo]);
	scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function() {
	$c.gus.cfInitHidVal(tbl_search);
  	ica_srchBudgetYm.setValue($c.date.getServerDateTime("yyyyMM"));
  	ica_srchBudgetYmTo.setValue($c.date.getServerDateTime("yyyyMM"));
	ica_srchBudgetYm.focus();
}

