scwin.f_Retrieve = async function() {

	//조회조건에 따른 필수체크 분기
	//hurrah015, 2013.03.29
	//alert(txt_srchAcctDeptNm.mandatory);

    let ret = await $c.gus.cfValidate([ed_coCd,ica_srchBudgetYm,ica_srchBudgetYmTo,ed_srchAcctDeptCd]);
    if (!ret) {
        return false;
    }

	if(ed_srchAcctDeptCd.getValue() == "" && ed_srchAcctDeptCd1.getValue() == ""){
		await $c.win.alert("[예산통제부서] 또는 [귀속부서] 둘중에 한가지 조건으로 \n\n조회하셔야 합니다.");
		if(ed_srchAcctDeptNm.getMandatory()){
			ed_srchAcctDeptCd.focus();
		}else{
			ed_srchAcctDeptCd1.focus();
		}
		return;
	}

	if(ed_srchAcctDeptNm.getMandatory()){
        let ret = await $c.gus.cfValidate([ica_srchBudgetYm
					   ,ica_srchBudgetYmTo
					   ,ed_srchAcctDeptCd])

