					 +"타 예산통제부서["+ed_srchAcctDeptCd.text+" - "+txt_srchAcctDeptNm.value+"]는 권한이 없습니다.");

					ds_master.ClearData();
					cfShowTotalRows(totalRows, 0);
					return;
				}
				*/
