				}else if (scwin.userId == '233113' ) { //김동균 과장 요청사항
					if (ed_srchAcctDeptCd.getValue() != '01506' && ed_srchAcctDeptCd.getValue() != '01536') {
						await $c.win.alert("로그인 하신 귀속부서의 예산통제부서는 ["+scwin.v_bugetCd+" - "+scwin.v_bugetNm+"] 입니다.\n\n"
						 +"타 예산통제부서["+ed_srchAcctDeptCd.getValue()+" - "+ed_srchAcctDeptNm.getValue()+"]는 권한이 없습니다.");

						ds_master.removeAll();
						totalRows.setValue(0);
						return;
					}

                // O-0171 추가 
                }else if (scwin.userId == '243014' ) { //이동규  요청사항
                    if (ed_srchAcctDeptCd.getValue() != '00896' && ed_srchAcctDeptCd.getValue() != '00047' && ed_srchAcctDeptCd.getValue() != '00140') {
                        await $c.win.alert("로그인 하신 귀속부서의 예산통제부서는 ["+scwin.v_bugetCd+" - "+scwin.v_bugetNm+"] 입니다.\n\n"
                            +"타 예산통제부서["+ed_srchAcctDeptCd.getValue()+" - "+ed_srchAcctDeptNm.getValue()+"]는 권한이 없습니다.");

						ds_master.removeAll();
						totalRows.setValue(0);
                        return;
                    }
                }else if (scwin.userId == '223039' ) { //김유준  요청사항
                    if (ed_srchAcctDeptCd.getValue() != '00896' && ed_srchAcctDeptCd.getValue() != '00047' && ed_srchAcctDeptCd.getValue() != '00140') {
                        await $c.win.alert("로그인 하신 귀속부서의 예산통제부서는 ["+scwin.v_bugetCd+" - "+scwin.v_bugetNm+"] 입니다.\n\n"
                            +"타 예산통제부서["+ed_srchAcctDeptCd.getValue()+" - "+ed_srchAcctDeptNm.getValue()+"]는 권한이 없습니다.");

						ds_master.removeAll();
						totalRows.setValue(0);
                        return;
                    }

				}else{
					await $c.win.alert("로그인 하신 귀속부서의 예산통제부서는 ["+scwin.v_bugetCd+" - "+scwin.v_bugetNm+"] 입니다.\n\n"
						 +"타 예산통제부서["+ed_srchAcctDeptCd.getValue()+" - "+ed_srchAcctDeptNm.getValue()+"]는 권한이 없습니다.");

					ds_master.removeAll();
					totalRows.setValue(0);
					return;
				}
			}
		}
	}else{
		if (!await $c.gus.cfValidate([ica_srchBudgetYm
					   ,ica_srchBudgetYmTo
					   ,ed_srchAcctDeptCd1]) == true) {
			return;
		}
	}

	//반영할 기간의 시작과 끝을 비교
  	if (ica_srchBudgetYm.getValue() > ica_srchBudgetYmTo.getValue()) {
  		await $c.win.alert("조회기간의 범위가 잘못되었습니다.");
  		ica_srchBudgetYm.focus();
  		return;
  	}
	//반영할 기간의 시작과 끝을 비교
  	if (ica_srchBudgetYm.getValue().substr(0,4) != ica_srchBudgetYmTo.getValue().substr(0,4)) {
  		await $c.win.alert("조회기간의 년도가 틀립니다.");
  		ica_srchBudgetYm.focus();
  		return;
  	}
	/*
	if (ed_srchAcctDeptCd.getValue() != ed_srchAcctDeptCd.hidVal)
	{
		await $c.win.alert("조회기간의 년도가 틀립니다." + ed_srchAcctDeptCd.Text+ed_srchAcctDeptCd.hidVal);	
		$c.win.alert(MSG_CM_ERR_038, ["부서코드"]);
		ed_srchAcctDeptCd.Focus();
		return false;
	}*/
	//dataSetDebug(ds_search, true);
	//ds_search.UseChangeInfo = false;
    $c.sbm.execute(sbm_search);
}

