scwin.f_Export = async function() {
    if (ds_master.getRowCount() == 0) {
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    let sheetTitle;
    let colCount = gr_master.getTotalCol();
    sheetTitle = "예산실적내역 (" + ica_srchBudgetYm.getValue() + " ~ " + ica_srchBudgetYmTo.getValue() + ")";

    let exportFileName = "예산실적내역_" + ica_srchBudgetYm.getValue() + "_" + ica_srchBudgetYmTo.getValue();

    let infoArr = [{
        rowIndex : 0, 
        colIndex : 0, 
        rowSpan : 1,
        colSpan : colCount, 
        text : sheetTitle, 
        textAlign : "center",
        fontSize : 18,
        drawBorder:false,
        color : "black",
        backgroundColor : "white"
    }];

    const options = {
        fileName: exportFileName + ".xlsx",
        sheetName: exportFileName,
        startRowIndex : 2,
        startColumnIndex : 0,
        columnMove:true,
        columnMoveWithFooter:true,
        type : 1
    }

    $c.data.downloadGridViewExcel(gr_master, options,infoArr);
};

